const app = document.getElementById('app');
const BASE_FREQ = {
  "1(A)": 440.0,
  "2(E)": 329.6275569,
  "3(C)": 261.6255653,
  "4(G)": 392.0
};

let tempoBpm = 72;
let audioCtx = null;
let isPlaying = false;
let playTimer = null;
let playIndex = 0;
let flatEvents = [];
let currentBarNo = 1;

function flattenScore(score) {
  const out = [];
  for (const bar of score) {
    for (const ev of bar.events) {
      out.push({ ...ev });
    }
  }
  return out;
}

flatEvents = flattenScore(SCORE);

function getEventIndexForBarStart(barNo) {
  const idx = flatEvents.findIndex(ev => ev.barNo === barNo);
  return idx >= 0 ? idx : 0;
}

function stepMs() {
  return 60000 / tempoBpm / 4;
}

function ensureAudio() {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  if (audioCtx.state === 'suspended') {
    audioCtx.resume();
  }
}

function pluckString(stringName, fret, when, velocity=0.22) {
  if (!audioCtx) return;
  const base = BASE_FREQ[stringName];
  const freq = base * Math.pow(2, fret / 12);

  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  const filter = audioCtx.createBiquadFilter();

  osc.type = 'triangle';
  osc.frequency.setValueAtTime(freq, when);

  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(2400, when);
  filter.Q.value = 0.7;

  gain.gain.setValueAtTime(0.0001, when);
  gain.gain.exponentialRampToValueAtTime(velocity, when + 0.005);
  gain.gain.exponentialRampToValueAtTime(0.0001, when + 1.1);

  osc.connect(filter);
  filter.connect(gain);
  gain.connect(audioCtx.destination);

  osc.start(when);
  osc.stop(when + 1.2);
}

function playEventSound(ev) {
  ensureAudio();
  const now = audioCtx.currentTime + 0.01;
  const order = ev.strum.includes('↑')
    ? ["1(A)","2(E)","3(C)","4(G)"]
    : ["4(G)","3(C)","2(E)","1(A)"];

  order.forEach((name, idx) => {
    const data = ev.strings[name];
    const fret = data && typeof data.fret === 'number' ? data.fret : 0;
    pluckString(name, fret, now + idx * 0.018, 0.18);
  });
}

function compareStrings(nowStrings, nextStrings) {
  const labels = ["1(A)","2(E)","3(C)","4(G)"];
  const rows = [];
  const fingerNames = [];
  const deltas = [];

  for (const label of labels) {
    const a = nowStrings[label] || { fret:0, finger:"" };
    const b = nextStrings[label] || { fret:0, finger:"" };
    if (a.fret === b.fret && (a.finger || "") === (b.finger || "")) {
      rows.push({ text: `${label}: そのまま`, type: 'stay' });
    } else {
      const left = `${a.fret}F${a.finger || ''}`;
      const right = `${b.fret}F${b.finger || ''}`;
      rows.push({ text: `${label}: ${left} → ${right}`, type: 'move' });
      if (a.finger && a.finger === b.finger) {
        fingerNames.push(a.finger);
      }
      deltas.push(b.fret - a.fret);
    }
  }

  let summary = '変わる弦だけ確認';
  if (deltas.length > 0 && deltas.every(d => d === deltas[0]) && [...new Set(fingerNames)].length >= 2) {
    const uniqueFingers = [...new Set(fingerNames)].join('・');
    const delta = deltas[0];
    if (delta === -1) summary = `${uniqueFingers}はそのまま 1F ずつ左へ`;
    else if (delta === 1) summary = `${uniqueFingers}はそのまま 1F ずつ右へ`;
    else if (delta < 0) summary = `${uniqueFingers}はそのまま ${Math.abs(delta)}F 左へ`;
    else if (delta > 0) summary = `${uniqueFingers}はそのまま ${Math.abs(delta)}F 右へ`;
  } else if (deltas.length === 0) {
    summary = 'そのまま維持';
  }

  return { summary, rows };
}

function cardTableHtml(strings, next=false) {
  const labels = ["1(A)","2(E)","3(C)","4(G)"];
  const headers = ['1F','2F','3F','4F'];
  const rows = labels.map(label => {
    const data = strings[label] || { fret:0, finger:'' };
    const cells = [1,2,3,4].map(f => {
      if (data.fret === 0 && f === 1) {
        return `<span class="chord-cell chord-cell-open">開放</span>`;
      }
      if (data.fret === f) {
        return `<span class="chord-cell chord-cell-hit ${next ? 'chord-cell-hit-next' : ''}">${data.finger || '●'}</span>`;
      }
      return `<span class="chord-cell"></span>`;
    }).join('');
    return `
      <div class="fret-row">
        <span class="fret-row-label">${label}</span>
        <div class="fret-row-cells">${cells}</div>
      </div>
    `;
  }).join('');

  return `
    <div class="chord-table-wrap ${next ? 'chord-table-wrap-next' : ''}">
      <div class="fret-header">
        <span class="fret-header-spacer"></span>
        <div class="fret-header-cells">${headers.map(h => `<span class="fret-header-cell">${h}</span>`).join('')}</div>
      </div>
      ${rows}
    </div>
  `;
}

function infoLinesHtml(strings) {
  const labels = ["1(A)","2(E)","3(C)","4(G)"];
  return labels.map(label => {
    const data = strings[label] || { fret:0, finger:'' };
    const txt = data.fret === 0 ? `${label}: 開放` : `${label}: ${data.fret}F ${data.finger || ''}`;
    return `<div class="chord-info-line">${txt}</div>`;
  }).join('');
}

function laneRowsHtml(barNo, playStep) {
  const bar = SCORE.find(b => b.barNo === barNo) || SCORE[0];
  const rowLabels = ["1(A)","2(E)","3(C)","4(G)"];
  return rowLabels.map(label => {
    const dots = bar.events.map(ev => {
      const left = 12 + (ev.i / 15) * 76;
      return `<span class="lane-note" style="left:${left}%"></span>`;
    }).join('');
    return `
      <div class="lane-row">
        <span class="lane-name">${label}</span>
        <div class="lane-track">${dots}</div>
      </div>
    `;
  }).join('');
}

function playheadLeft(step) {
  return 12 + (step / 15) * 76;
}

function render() {
  const current = flatEvents[playIndex] || flatEvents[0];
  const next = flatEvents[Math.min(playIndex + 1, flatEvents.length - 1)] || current;
  currentBarNo = current.barNo;

  const compared = compareStrings(current.strings, next.strings);
  const beatNo = Math.floor(current.i / 4) + 1;

  app.innerHTML = `
    <div class="practice-shell">
      <header class="practice-topbar">
        <div class="topbar-left">
          <p class="eyebrow">PRACTICE</p>
          <h1>12th Street Rag</h1>
          <p class="topbar-sub">4/4 / swing / 5-8小節 / ループ中</p>
        </div>
        <div class="topbar-right">
          <div class="top-chip" id="bpmChip">BPM ${tempoBpm}</div>
          <div class="top-chip top-chip-active">Pulse Split</div>
          <div class="top-chip">★★★</div>
        </div>
      </header>

      <div class="practice-layout">
        <section class="practice-card side-card">
          <div class="card-head">
            <span class="card-head-label">NOW</span>
            <span class="card-head-dot"></span>
          </div>
          <div class="shape-name">${current.chord || ''}</div>
          ${cardTableHtml(current.strings, false)}
          <div class="shape-meta shape-meta-lines">${infoLinesHtml(current.strings)}</div>
          <div class="shape-line shape-line-hint"><span class="shape-label">ヒント</span><strong>そのまま維持</strong></div>
        </section>

        <section class="practice-card center-card">
          <div class="card-head">
            <span class="card-head-label">4弦レーン</span>
            <span class="card-head-dot"></span>
          </div>

          <div class="rhythm-line">
            <div class="rhythm-col"><span class="rhythm-beat">1拍目</span><span class="rhythm-hit">↓</span></div>
            <div class="rhythm-col"><span class="rhythm-beat">2拍目</span><span class="rhythm-hit">↓↑</span></div>
            <div class="rhythm-col"><span class="rhythm-beat">3拍目</span><span class="rhythm-hit">↓</span></div>
            <div class="rhythm-col"><span class="rhythm-beat">4拍目</span><span class="rhythm-hit">↑</span></div>
          </div>

          <div class="lane-box">
            ${laneRowsHtml(current.barNo, current.i)}
            <div class="playhead" style="left:${playheadLeft(current.i)}%"></div>
          </div>

          <div class="lane-hint">
            <span class="lane-hint-label">現在</span>
            <strong>${current.barNo}小節目 / ${beatNo}拍目</strong>
          </div>
        </section>

        <section class="practice-card side-card next-card">
          <div class="card-head">
            <span class="card-head-label">NEXT</span>
            <span class="card-head-dot card-head-dot-next"></span>
          </div>
          <div class="shape-name shape-name-next">${next.chord || ''}</div>
          ${cardTableHtml(next.strings, true)}
          <div class="change-summary-banner">${compared.summary}</div>
          <div class="change-box">
            <div class="change-box-title">ゆっくり確認</div>
            <div class="change-box-lines">
              ${compared.rows.map(r => `<div class="change-line ${r.type === 'stay' ? 'change-line-stay' : 'change-line-move'}">${r.text}</div>`).join('')}
            </div>
          </div>
        </section>
      </div>

      <footer class="transport">
        <button class="transport-btn" id="backBtn" type="button">戻る</button>
        <button class="transport-btn" id="replayBtn" type="button">もう一回</button>
        <button class="transport-btn transport-btn-primary" id="playBtn" type="button">${isPlaying ? '停止' : '再生 / 停止'}</button>
        <button class="transport-btn" id="nextBtn" type="button">次へ</button>
        <button class="transport-btn" id="slowBtn" type="button">遅く</button>
        <button class="transport-btn" id="fastBtn" type="button">速く</button>
        <button class="transport-btn transport-btn-voice" type="button">🎤</button>
      </footer>
    </div>
  `;
  bindEvents();
}

function stopPlayback() {
  isPlaying = false;
  if (playTimer) {
    clearTimeout(playTimer);
    playTimer = null;
  }
  render();
}

function scheduleNextStep() {
  if (!isPlaying) return;
  const current = flatEvents[playIndex];
  if (!current) {
    stopPlayback();
    return;
  }
  playEventSound(current);
  render();
  playIndex += 1;
  if (playIndex >= flatEvents.length) {
    stopPlayback();
    playIndex = flatEvents.length - 1;
    render();
    return;
  }
  const currentStepAbs = current.barNo * 16 + current.i;
  const next = flatEvents[playIndex];
  const nextStepAbs = next.barNo * 16 + next.i;
  const deltaSteps = Math.max(1, nextStepAbs - currentStepAbs);
  playTimer = setTimeout(scheduleNextStep, stepMs() * deltaSteps);
}

function startPlayback() {
  ensureAudio();
  isPlaying = true;
  scheduleNextStep();
  render();
}

function bindEvents() {
  document.getElementById('playBtn')?.addEventListener('click', () => {
    if (isPlaying) stopPlayback();
    else startPlayback();
  });

  document.getElementById('backBtn')?.addEventListener('click', () => {
    stopPlayback();
    playIndex = Math.max(0, playIndex - 1);
    render();
  });

  document.getElementById('replayBtn')?.addEventListener('click', () => {
    stopPlayback();
    const current = flatEvents[playIndex] || flatEvents[0];
    playIndex = getEventIndexForBarStart(current.barNo);
    render();
  });

  document.getElementById('nextBtn')?.addEventListener('click', () => {
    stopPlayback();
    const current = flatEvents[playIndex] || flatEvents[0];
    const targetBar = Math.min(SCORE[SCORE.length - 1].barNo, current.barNo + 1);
    playIndex = getEventIndexForBarStart(targetBar);
    render();
  });

  document.getElementById('slowBtn')?.addEventListener('click', () => {
    tempoBpm = Math.max(40, tempoBpm - 4);
    render();
  });

  document.getElementById('fastBtn')?.addEventListener('click', () => {
    tempoBpm = Math.min(160, tempoBpm + 4);
    render();
  });
}

render();
